/* oms-master-owOrTypeMapp-sql-oracle.xml selectOwOrMappType */
SELECT EXTORDERTYPECD AS FIELD1
     , EXTORDERTYPECD||':'||EXTORDERTYPENM AS FIELD2
  FROM TORDER_MST_EXTERN
 WHERE OWKEY = #{owkey}      
 ORDER BY EXTORDERTYPECD

