mapper.update:
/* oms-order-customerOrder-sql-oracle.xml - deleteExcelTempDetailList */ UPDATE TORDER_UPLOAD_CUSTOMER TUM SET DELYN = ( SELECT TB.DELYN FROM ( SELECT 'Y' AS DELYN , T.UPLOADKEY , T.UPLOADSEQ FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ ) T ) TB WHERE TB.UPLOADKEY = TUM.UPLOADKEY AND TB.UPLOADSEQ = TUM.UPLOADSEQ ) WHERE TUM.UPLOADKEY = #{uploadkey} AND EXISTS ( SELECT 1 FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ ) T WHERE T.UPLOADSEQ = TUM.UPLOADSEQ )

mapper.delete:
/* oms-order-customerOrder-sql-oracle.xml - deleteExcelTemp */
DELETE FROM TORDER_UPLOAD_CUSTOMER
WHERE UPLOADKEY = #{uploadkey}

mapper.select:
/* oms-order-customerOrder-sql-oracle.xml - selectExcelErrorCount */
SELECT COUNT(1)
FROM TORDER_UPLOAD_CUSTOMER
WHERE UPLOADKEY = #{uploadkey}
  AND DELYN = 'N'
  AND ORDER_ERROR_CD IS NOT NULL

mapper.update:
/* oms-order-customerOrder-sql-oracle.xml - updateCustomerOrderReturn */
UPDATE TORDER_INFO_CO_HD
   SET OCCURRENCE_ORDER_YN = 'Y'
WHERE CUSTOMERORDERKEY = #{customerorderkey}

mapper.select:
/* oms-order-customerOrder-sql-oracle.xml - selectCustomerOrderNumList */
SELECT ORDER_GROUP
     , TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') || #{orderNoType} || LPAD(nextval('seq_torder_info_co_hd')::TEXT, 6, '0') AS CUSTOMERORDERKEY
FROM (
    SELECT T.ORDER_GROUP
    FROM ( 
                SELECT #{item.orderGroup} AS ORDER_GROUP
             ) T
    ORDER BY LPAD(T.ORDER_GROUP::TEXT, 10, 0) ASC
     )

/* oms-order-customerOrder-sql-oracle.xml selectMultiCustomerOrderList */ SELECT CH.EXTERNORDERKEY , COUNT(1) AS CNT FROM TORDER_INFO_CO_HD CH JOIN TORDER_INFO_CO_HD RCH ON CH.OWKEY = RCH.OWKEY AND CH.EXTERNORDERKEY = RCH.EXTERNORDERKEY AND RCH.WKSTATUS NOT IN
#{status}
WHERE CH.OWKEY = #{owkey} AND CH.CUSTOMERORDERKEY IN
#{customerorderkey}
GROUP BY CH.EXTERNORDERKEY HAVING COUNT(1) > 1

/* oms-order-customerOrder-sql-oracle.xml - selectSendedOrderList */ SELECT CH.OWKEY , CH.COHDKEY , CASE WHEN CH.WKSTATUS=#{completeStatus} THEN 'Y' ELSE 'N' END AS SAVEYN , CASE WHEN CH.ERPSNDFAILYN = 'P' THEN 'N' /*보류해제*/ ELSE 'P' /*보류*/ END AS ERPSNDFAILYN , CH.WKSTATUS , SH.SOHDKEY FROM (
SELECT #{item.cohdkey} AS COHDKEY
) T JOIN TORDER_INFO_CO_HD CH ON T.COHDKEY = CH.COHDKEY AND CH.OWKEY = #{owkey} LEFT JOIN TORDER_INFO_SO_HD SH ON CH.OWKEY = SH.OWKEY AND CH.COHDKEY = SH.COHDKEY AND SH.CNLYN = 'N'
